export class Tool extends Component {
  state = {
    index: '',
    hovered: false
  };

  render() {
    return (
      <div className="columns is-mobile is-tablet is-desktop is-multiline">
        {list.map((tool, i) => (
          <div key={i} className="column is-4-mobile is-3-tablet is-2-desktop">
            <a href={tool.link} target="_blank" rel="noopener noreferrer">
              <img
                className={
                  this.state.hovered && this.state.index === i
                    ? 'animated pulse infinite'
                    : ''
                }
                onMouseEnter={() => this.setState({ index: i, hovered: true })}
                onMouseLeave={() => this.setState({ index: i, hovered: false })}
                src={tool.img}
                alt=""
              />
            </a>
          </div>
        ))}
      </div>
    );
  }
}

export default Tool;
